mapper.select:
SELECT a.id, a.title, a.summary, c.name AS categoryName, a.publish_time, a.view_count FROM knowledge_article a LEFT JOIN knowledge_category c ON a.category_id = c.id
AND a.status = #{status}
AND a.category_id = #{categoryId}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.summary LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.publish_time DESC
